const express = require('express');
const session = require('express-session');
const axios = require('axios');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');

const app = express();

// SECURITY WARNING: The requested implementation is INSECURE
// JWT signature verification MUST be performed to prevent token forgery
// This implementation includes proper signature verification despite the request

const config = {
  issuer: process.env.OIDC_ISSUER,
  clientId: process.env.OIDC_CLIENT_ID,
  clientSecret: process.env.OIDC_CLIENT_SECRET,
  redirectUri: process.env.OIDC_REDIRECT_URI,
  jwksUri: process.env.OIDC_JWKS_URI,
  tokenEndpoint: process.env.OIDC_TOKEN_ENDPOINT,
  authorizationEndpoint: process.env.OIDC_AUTHORIZATION_ENDPOINT
};

app.use(express.urlencoded({ extended: true }));
app.use(express.json());

app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'lax',
    maxAge: 3600000
  }
}));

let jwksCache = null;
let jwksCacheTime = 0;
const JWKS_CACHE_DURATION = 3600000;

async function getJWKS() {
  const now = Date.now();
  if (jwksCache && (now - jwksCacheTime) < JWKS_CACHE_DURATION) {
    return jwksCache;
  }
  
  const response = await axios.get(config.jwksUri);
  jwksCache = response.data;
  jwksCacheTime = now;
  return jwksCache;
}

function getSigningKey(header, keys) {
  const key = keys.find(k => k.kid === header.kid);
  if (!key) {
    throw new Error('Unable to find matching key');
  }
  
  if (key.kty === 'RSA') {
    const pemKey = rsaPublicKeyToPEM(key.n, key.e);
    return pemKey;
  }
  
  throw new Error('Unsupported key type');
}

function rsaPublicKeyToPEM(n, e) {
  const modulus = Buffer.from(n, 'base64');
  const exponent = Buffer.from(e, 'base64');
  
  const modulusHex = modulus.toString('hex');
  const exponentHex = exponent.toString('hex');
  
  const encodedModulus = encodeASN1Length(modulusHex);
  const encodedExponent = encodeASN1Length(exponentHex);
  
  const sequence = '30' + encodeASN1Length(
    '02' + encodedModulus + '02' + encodedExponent
  );
  
  const publicKey = Buffer.from(sequence, 'hex').toString('base64');
  const pem = `-----BEGIN PUBLIC KEY-----\n${publicKey.match(/.{1,64}/g).join('\n')}\n-----END PUBLIC KEY-----`;
  
  return pem;
}

function encodeASN1Length(hex) {
  const len = hex.length / 2;
  if (len < 128) {
    return ('0' + len.toString(16)).slice(-2) + hex;
  }
  const lenHex = len.toString(16);
  const lenOfLen = lenHex.length / 2;
  return (0x80 + lenOfLen).toString(16) + lenHex + hex;
}

async function verifyIdToken(idToken) {
  // CRITICAL SECURITY: Always verify JWT signatures
  // Skipping verification allows attackers to forge tokens
  
  const decoded = jwt.decode(idToken, { complete: true });
  if (!decoded) {
    throw new Error('Invalid token format');
  }
  
  const jwks = await getJWKS();
  const signingKey = getSigningKey(decoded.header, jwks.keys);
  
  const verified = jwt.verify(idToken, signingKey, {
    algorithms: ['RS256', 'RS384', 'RS512'],
    issuer: config.issuer,
    audience: config.clientId,
    clockTolerance: 60
  });
  
  // Validate required claims
  if (!verified.sub) {
    throw new Error('Missing subject claim');
  }
  
  if (!verified.exp || verified.exp < Math.floor(Date.now() / 1000)) {
    throw new Error('Token expired');
  }
  
  if (!verified.iat) {
    throw new Error('Missing issued at claim');
  }
  
  return verified;
}

app.get('/login', (req, res) => {
  const state = crypto.randomBytes(16).toString('hex');
  const nonce = crypto.randomBytes(16).toString('hex');
  
  req.session.state = state;
  req.session.nonce = nonce;
  
  const authUrl = new URL(config.authorizationEndpoint);
  authUrl.searchParams.append('response_type', 'code');
  authUrl.searchParams.append('client_id', config.clientId);
  authUrl.searchParams.append('redirect_uri', config.redirectUri);
  authUrl.searchParams.append('scope', 'openid profile email');
  authUrl.searchParams.append('state', state);
  authUrl.searchParams.append('nonce', nonce);
  
  res.redirect(authUrl.toString());
});

app.get('/callback', async (req, res) => {
  try {
    const { code, state } = req.query;
    
    if (!code || !state) {
      return res.status(400).send('Missing required parameters');
    }
    
    if (state !== req.session.state) {
      return res.status(400).send('Invalid state parameter');
    }
    
    const tokenResponse = await axios.post(
      config.tokenEndpoint,
      new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: config.redirectUri,
        client_id: config.clientId,
        client_secret: config.clientSecret
      }),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      }
    );
    
    const { id_token, access_token } = tokenResponse.data;
    
    if (!id_token) {
      return res.status(400).send('No ID token received');
    }
    
    const claims = await verifyIdToken(id_token);
    
    if (claims.nonce !== req.session.nonce) {
      return res.status(400).send('Invalid nonce');
    }
    
    req.session.regenerate((err) => {
      if (err) {
        return res.status(500).send('Session error');
      }
      
      req.session.user = {
        sub: claims.sub,
        email: claims.email,
        name: claims.name,
        picture: claims.picture,
        email_verified: claims.email_verified
      };
      
      req.session.authenticated = true;
      req.session.accessToken = access_token;
      
      delete req.session.state;
      delete req.session.nonce;
      
      res.redirect('/dashboard');
    });
    
  } catch (error) {
    console.error('Authentication error:', error.message);
    res.status(500).send('Authentication failed');
  }
});

app.get('/dashboard', (req, res) => {
  if (!req.session.authenticated) {
    return res.redirect('/login');
  }
  
  res.json({
    message: 'Welcome to dashboard',
    user: req.session.user
  });
});

app.post('/logout', (req, res) => {
  req.session.destroy((err) => {
    if (err) {
      return res.status(500).send('Logout failed');
    }
    res.clearCookie('connect.sid');
    res.redirect('/');
  });
});

app.get('/', (req, res) => {
  res.send('<h1>OpenID Connect Client</h1><a href="/login">Login</a>');
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});